local _bxor = (bit32 and bit32.bxor) or function(a, b)
  local r, bit = 0, 1
  while a > 0 or b > 0 do
    local aa = a % 2
    local bb = b % 2
    if aa ~= bb then r = r + bit end
    a = (a - aa) / 2
    b = (b - bb) / 2
    bit = bit * 2
  end
  return r
end
